/* quiz-data-extra5.js — completamento vpn, ipsec, firewall, acl, ids-ips, cloud, packet-tracer */
window.QUIZ_DATA_EXTRA5 = {

"vpn":[
  {id:200,type:"mc",topic:"Tunneling",text:"Quale protocollo VPN incapsula frame di livello 2 dentro un tunnel IP?",options:["IPsec","L2TP","WireGuard","IKEv2"],correct:1,explanation:"L2TP (Layer 2 Tunneling Protocol) incapsula frame L2 (Ethernet, PPP) dentro UDP/IP. Di per sé non cifra — si usa L2TP/IPsec per la sicurezza."},
  {id:201,type:"mc",topic:"Sicurezza",text:"Quale metodo di autenticazione VPN è il più sicuro?",options:["PSK (pre-shared key)","Username/password","Certificati digitali X.509","Solo biometria"],correct:2,explanation:"I certificati digitali X.509 offrono la massima sicurezza: basati su crittografia a chiave pubblica, non condivisi tra utenti, revocabili individualmente. PSK è meno sicuro perché condiviso tra tutti gli utenti."},
  {id:202,type:"mc",topic:"Tipologie",text:"In una VPN Site-to-Site, chi stabilisce il tunnel?",options:["I singoli utenti","I gateway VPN di entrambe le sedi","Il server DNS aziendale","Il provider Internet"],correct:1,explanation:"Site-to-Site VPN: i gateway VPN (router/firewall con funzione VPN) di entrambe le sedi stabiliscono il tunnel. È trasparente agli utenti finali."},
  {id:203,type:"mc",topic:"Protocolli",text:"OpenVPN supporta quale porta?",options:["Solo UDP 1194","Solo TCP 443","Qualsiasi porta TCP o UDP (configurabile)","Solo UDP 500"],correct:2,explanation:"OpenVPN è flessibile: può usare qualsiasi porta TCP o UDP. Spesso si usa UDP 1194 (default) o TCP 443 (per attraversare firewall restrittivi che bloccano solo porte non-HTTPS)."},
  {id:204,type:"mc",topic:"Sicurezza",text:"Quale tipo di VPN è più difficile da rilevare e bloccare dai firewall aziendali?",options:["IPsec su UDP 500","L2TP/IPsec","SSL VPN su porta 443","PPTP"],correct:2,explanation:"SSL VPN su porta 443: usa HTTPS, indistinguibile dal traffico web normale. I firewall che permettono HTTPS non possono bloccarlo senza interrompere anche la navigazione web."},
  {id:205,type:"mc",topic:"Confronto",text:"WireGuard rispetto a IPsec è:",options:["Più complesso","Con codice base molto più snello (~4000 righe vs ~400.000)","Più antico","Meno sicuro"],correct:1,explanation:"WireGuard: ~4000 righe di codice. IPsec (con IKE, ESP, AH, librerie): ~400.000+ righe. Meno codice = meno superficie d'attacco, più facile da auditare formalmente."},
  {id:206,type:"mc",topic:"Tunneling",text:"Quale campo dell'header IP viene modificato durante il tunneling VPN?",options:["TTL","IP sorgente e destinazione (vengono sostituiti con gli IP del gateway)","Checksum TCP","Numero di porta"],correct:1,explanation:"In tunnel mode, l'header IP originale viene cifrato dentro il payload. Il nuovo pacchetto ha IP sorgente = gateway VPN locale e IP destinazione = gateway VPN remoto."},
  {id:207,type:"tf",topic:"Sicurezza",text:"Una VPN garantisce sempre anonimato completo su Internet.",options:["Vero","Falso"],correct:1,explanation:"FALSO. Una VPN protegge il traffico dall'ISP locale e nasconde l'IP reale ai siti visitati, ma non garantisce anonimato completo: il provider VPN può vedere il traffico, cookie e fingerprinting identificano l'utente."},
  {id:208,type:"mc",topic:"Protocolli",text:"IKEv2 rispetto a IKEv1 ha quale vantaggio principale?",options:["Più vecchio e testato","Più messaggi per maggiore sicurezza","Handshake più efficiente (4 messaggi), supporto NAT-T nativo, MOBIKE","Usa TCP invece di UDP"],correct:2,explanation:"IKEv2: 4 messaggi (vs 6 in Main Mode IKEv1), NAT-T nativo, MOBIKE (mobilità, cambia IP senza perdere VPN), EAP per autenticazione avanzata, keepalive integrato."},
  {id:209,type:"mc",topic:"Tipologie",text:"Quale VPN è la più adatta per connettere filiali bancarie a un datacenter centrale?",options:["Remote-Access VPN","Site-to-Site IPsec VPN","SSL VPN via browser","PPTP"],correct:1,explanation:"Site-to-Site IPsec VPN: connessione permanente e ad alta sicurezza tra le filiali e il datacenter. IPsec garantisce cifratura forte e autenticazione. Trasparente agli utenti delle filiali."},
  {id:210,type:"mc",topic:"Sicurezza",text:"Cosa è il 'split tunneling' in una VPN?",options:["Dividere il tunnel in due","Configurazione che invia solo il traffico aziendale nel tunnel VPN, il resto direttamente a Internet","Un tipo di attacco","Una tecnica di bilanciamento del carico"],correct:1,explanation:"Split tunneling: solo il traffico verso la rete aziendale passa nel tunnel VPN, il traffico verso Internet va direttamente senza VPN. Migliora le prestazioni ma riduce la visibilità dell'azienda sul traffico Internet dei dipendenti."},
  {id:211,type:"mc",topic:"Protocolli",text:"Quale porta usa IKE di default?",options:["TCP 179","UDP 500","TCP 443","UDP 4500"],correct:1,explanation:"IKE (Internet Key Exchange) usa UDP porta 500. Con NAT-T (NAT Traversal) passa a UDP porta 4500 per incapsulare ESP dentro UDP e attraversare i dispositivi NAT."},
  {id:212,type:"mc",topic:"Confronto",text:"Quale protocollo VPN è integrato nativamente nel kernel Linux >= 5.6?",options:["OpenVPN","IPsec","WireGuard","L2TP"],correct:2,explanation:"WireGuard è stato integrato nel kernel Linux 5.6 (marzo 2020). Questo lo rende più efficiente di OpenVPN (userspace) e disponibile out-of-the-box sulle distribuzioni Linux moderne."},
  {id:213,type:"mc",topic:"Sicurezza",text:"Il 'Perfect Forward Secrecy' in una VPN garantisce che:",options:["Il traffico è sempre cifrato","La compromissione della chiave a lungo termine non espone il traffico passato","La VPN non perde mai pacchetti","L'autenticazione è sempre riuscita"],correct:1,explanation:"PFS: chiavi di sessione effimere, generate per ogni connessione e mai salvate. Se la chiave privata del server viene rubata in futuro, le sessioni VPN passate non sono decifrabili."},
  {id:214,type:"mc",topic:"Tipologie",text:"Una 'clientless VPN SSL' funziona tramite:",options:["Un client VPN dedicato da installare","Solo il browser web","Un app mobile","Una smart card"],correct:1,explanation:"Clientless SSL VPN: funziona tramite il browser web HTTPS senza necessità di installare client VPN. Il gateway VPN SSL serve come proxy web, reindirizzando il traffico verso le applicazioni interne."},
  {id:215,type:"mc",topic:"Sicurezza",text:"Quale metodo viene usato per autenticare i gateway in una VPN IPsec site-to-site?",options:["Solo username/password","PSK o certificati digitali X.509","Solo biometria","OTP via SMS"],correct:1,explanation:"VPN site-to-site IPsec: i gateway si autenticano con PSK (Pre-Shared Key — stessa password configurata su entrambi) o certificati digitali X.509 (più scalabile per molte filiali)."},
  {id:216,type:"mc",topic:"Tunneling",text:"In tunnel mode IPsec, l'header IP originale è:",options:["Visibile","Cifrato e incapsulato nel payload del nuovo pacchetto","Rimosso definitivamente","Duplicato"],correct:1,explanation:"Tunnel mode: il pacchetto originale completo (header IP + payload) viene cifrato da ESP e incapsulato come payload in un nuovo pacchetto IP. Gli IP originali non sono visibili all'esterno."},
  {id:217,type:"mc",topic:"Confronto",text:"Quale VPN protocol è sconsigliato per nuove implementazioni per motivi di sicurezza?",options:["IPsec","WireGuard","OpenVPN","PPTP"],correct:3,explanation:"PPTP (Point-to-Point Tunneling Protocol): usa MS-CHAPv2 vulnerabile, MPPE per la cifratura debole. Violato più volte, deprecato. Non usare mai per applicazioni di sicurezza moderne."},
  {id:218,type:"mc",topic:"Sicurezza",text:"Rekeying in una VPN significa:",options:["Cambiare il gateway VPN","Rinnovare le chiavi di sessione periodicamente durante la connessione","Ri-autenticare l'utente","Cambiare il protocollo VPN"],correct:1,explanation:"Rekeying: il processo di generare e negoziare nuove chiavi di sessione durante una VPN attiva, senza interrompere la connessione. Riduce l'esposizione nel caso una chiave venga compromessa."},
  {id:219,type:"mc",topic:"Tipologie",text:"Quale tecnologia permette di connettere filiali senza configurare VPN manualmente, usando policy centralizzate?",options:["PPTP","L2TP","SD-WAN","Solo IPsec manuale"],correct:2,explanation:"SD-WAN (Software-Defined WAN): gestione centralizzata delle connessioni WAN con routing intelligente, QoS, e VPN automatiche tra le sedi. Supera le VPN site-to-site tradizionali per flessibilità e gestione."},
  {id:220,type:"mc",topic:"Sicurezza",text:"Quale è il vantaggio principale di usare certificati X.509 rispetto ai PSK per una VPN?",options:["I certificati sono più veloci","I certificati sono revocabili individualmente e scalano meglio con molti utenti","I PSK sono meno sicuri in assoluto","Non c'è differenza pratica"],correct:1,explanation:"Certificati X.509: ogni utente/gateway ha il proprio certificato, revocabile individualmente senza impatto sugli altri. Con PSK, tutti condividono la stessa chiave — se un dispositivo è compromesso, occorre cambiare la chiave su TUTTI."},
  {id:221,type:"mc",topic:"Confronto",text:"SSTP (Secure Socket Tunneling Protocol) è proprietario di quale vendor?",options:["Cisco","Juniper","Microsoft","OpenSource"],correct:2,explanation:"SSTP è un protocollo VPN proprietario Microsoft. Usa HTTPS (SSL/TLS sopra TCP 443), ideale per ambienti Windows. Non supportato su Linux/macOS nativamente."},
  {id:222,type:"mc",topic:"Tunneling",text:"Quale protocollo di tunneling usa GRE (Generic Routing Encapsulation)?",options:["VPN ad uso esclusivo","Tunneling senza cifratura, spesso combinato con IPsec","HTTPS cifrato","PPTP interno"],correct:1,explanation:"GRE encapsula vari protocolli di rete (anche non-IP) dentro IP. Non cifra. Spesso usato con IPsec: GRE crea il tunnel, IPsec cifra il traffico GRE."},
  {id:223,type:"mc",topic:"Sicurezza",text:"Cosa è un 'VPN concentrator'?",options:["Un router normale","Un dispositivo dedicato che gestisce molte sessioni VPN simultanee","Un tipo di firewall","Un server DNS"],correct:1,explanation:"VPN concentrator: dispositivo hardware dedicato ottimizzato per terminare e gestire grandi numeri di sessioni VPN simultanee. Usato in aziende con molti utenti remoti. Es. Cisco ASA, Palo Alto."},
  {id:224,type:"mc",topic:"Confronto",text:"Quale differenza c'è tra una VPN IPsec e una VPN SSL/TLS in termini di visibilità alle applicazioni?",options:["Nessuna differenza","IPsec è trasparente a tutte le applicazioni (L3), SSL richiede support applicativo (L7)","SSL è trasparente, IPsec no","Entrambi richiedono modifiche applicative"],correct:1,explanation:"IPsec (L3): trasparente — tutte le applicazioni usano la rete normalmente senza saperlo. SSL/TLS VPN (L7): le applicazioni devono essere accessibili tramite web browser o client specifico."},
  {id:225,type:"mc",topic:"Protocolli",text:"Quale VPN protocol è nato specificamente per ambienti mobile (cambio IP senza perdere VPN)?",options:["L2TP","PPTP","IKEv2 con MOBIKE","OpenVPN"],correct:2,explanation:"IKEv2 con MOBIKE (RFC 4555): permette a un client mobile di cambiare indirizzo IP (es. passando da Wi-Fi a 4G) senza interrompere la sessione VPN."},
  {id:226,type:"tf",topic:"Sicurezza",text:"Una VPN cifra anche il traffico DNS, proteggendo la privacy delle query DNS.",options:["Vero","Falso"],correct:0,explanation:"VERO (se configurata correttamente). Una VPN ben configurata instrada le query DNS attraverso il tunnel cifrato verso il DNS server aziendale o privato, prevenendo il DNS leaking."},
  {id:227,type:"mc",topic:"Tipologie",text:"Quale è il principale caso d'uso di una 'Extranet VPN'?",options:["Connettere rami interni","Connettere partner esterni, fornitori o clienti alla rete aziendale","Collegare solo utenti remoti","Backup dei dati"],correct:1,explanation:"Extranet VPN: estende la rete aziendale verso partner commerciali, fornitori, clienti con accesso controllato. Diverso dall'intranet VPN (solo dipendenti interni) e remote-access VPN."},
  {id:228,type:"mc",topic:"Sicurezza",text:"Quale strumento può aiutare a verificare che la VPN non abbia DNS leak?",options:["ping","nmap","dnsleaktest.com o ipleak.net","traceroute"],correct:2,explanation:"DNS leak test: verifica che le query DNS viaggino attraverso la VPN e non vengano inviate all'ISP locale. Strumenti: dnsleaktest.com, ipleak.net, dnsleak.com."},
  {id:229,type:"mc",topic:"Confronto",text:"Quale VPN protocol usa la porta UDP 51820 di default?",options:["IPsec","OpenVPN","WireGuard","L2TP"],correct:2,explanation:"WireGuard usa UDP porta 51820 di default. Può essere cambiata nella configurazione. UDP è più efficiente di TCP per VPN (no doppio controllo di flusso con TCP interno)."},
],

"ipsec":[
  {id:200,type:"mc",topic:"SA",text:"La SA in IPsec identifica:",options:["Il router remoto","Un canale unidirezionale con parametri e chiavi specifiche","Una connessione bidirezionale","Un certificato digitale"],correct:1,explanation:"SA (Security Association): canale unidirezionale. Identificata da: SPI (Security Parameter Index) + IP destinazione + protocollo (AH o ESP). Per comunicazione bidirezionale servono 2 SA."},
  {id:201,type:"mc",topic:"IKE",text:"Quale versione di IKE usa solo 4 messaggi per la Fase 1?",options:["IKEv1 Main Mode","IKEv1 Aggressive Mode","IKEv2","IKEv3"],correct:2,explanation:"IKEv2: usa 4 messaggi (2 scambi) per stabilire l'IKE SA, contro 6 di IKEv1 Main Mode o 3 di Aggressive Mode. IKEv2 è anche più robusto e supporta MOBIKE, EAP, NAT-T nativo."},
  {id:202,type:"mc",topic:"Protocolli",text:"Quale numero di protocollo IP usa ESP?",options:["47","50","51","89"],correct:1,explanation:"ESP usa IP protocollo 50. AH usa IP protocollo 51. GRE usa 47. OSPF usa 89. Questi si trovano nel campo 'Protocol' dell'header IP."},
  {id:203,type:"mc",topic:"Modalità",text:"La modalità trasporto IPsec viene usata tipicamente per:",options:["VPN site-to-site tra gateway","Connessioni host-to-host (es. entre due server nello stesso datacenter)","Tutte le VPN","Solo con AH"],correct:1,explanation:"Modalità trasporto: protegge solo il payload, l'header IP originale rimane visibile. Ideale per comunicazioni host-to-host dove la privacy degli IP non è necessaria."},
  {id:204,type:"mc",topic:"IKE",text:"Cosa fa l'algoritmo DH in IKE?",options:["Autentica le parti","Permette di derivare una chiave condivisa senza trasmetterla","Cifra i dati","Verifica i certificati"],correct:1,explanation:"DH in IKE: genera materiale crittografico condiviso (la chiave DH) senza mai trasmettere la chiave stessa. La chiave viene poi usata per derivare le chiavi IKE."},
  {id:205,type:"mc",topic:"Protocolli",text:"AH non funziona con NAT perché:",options:["NAT usa porte diverse","NAT modifica l'IP sorgente nell'header, invalidando l'autenticazione AH che include l'header IP","AH è troppo vecchio","AH usa una porta riservata"],correct:1,explanation:"AH autentica l'intero pacchetto incluso l'header IP (eccetto i campi mutabili come TTL). NAT modifica l'IP sorgente → l'hash di autenticazione AH non corrisponde più → pacchetto scartato."},
  {id:206,type:"mc",topic:"IKE",text:"Quick Mode (IKE Fase 2) è protetto da:",options:["Nessuna protezione","Il canale IKE SA stabilito in Fase 1","La connessione TCP","Il certificato del server"],correct:1,explanation:"Quick Mode avviene all'interno del tunnel sicuro stabilito in IKE Fase 1 (ISAKMP SA). Tutti i messaggi Quick Mode sono cifrati e autenticati con le chiavi della Fase 1."},
  {id:207,type:"mc",topic:"SA",text:"Cosa è il SAD (Security Association Database)?",options:["Il database DNS di sicurezza","Database che contiene tutte le SA attive con parametri e chiavi","La tabella di routing IPsec","Il certificato del gateway"],correct:1,explanation:"SAD: database in-kernel che contiene tutte le SA attive. Per ogni pacchetto in uscita o in arrivo, IPsec consulta il SAD per trovare la SA appropriata e applicare le trasformazioni di sicurezza."},
  {id:208,type:"mc",topic:"IKE",text:"Quale è la differenza principale tra IKEv1 Aggressive Mode e Main Mode?",options:["Aggressive Mode è più sicuro","Aggressive Mode usa 3 messaggi con identità in chiaro, Main Mode 6 con identità protetta","Aggressive Mode usa TCP","Main Mode è più veloce"],correct:1,explanation:"Main Mode: 6 messaggi, identità cifrate dopo lo scambio DH. Più sicuro ma più lento. Aggressive Mode: 3 messaggi, identità trasmesse nel primo messaggio (in chiaro). Più veloce ma meno sicuro."},
  {id:209,type:"mc",topic:"Protocolli",text:"Quale protocollo IPsec viene usato nelle VPN moderne?",options:["AH da solo","ESP con HMAC","AH + ESP insieme","Solo IKE"],correct:1,explanation:"ESP (IP 50) con HMAC: fornisce cifratura (AES) + autenticazione (HMAC-SHA256). È lo standard nelle VPN moderne. AH da solo non cifra e ha problemi con NAT. ESP da solo (senza auth) è sconsigliato."},
  {id:210,type:"mc",topic:"IKE",text:"Cosa è il PSK (Pre-Shared Key) in IPsec?",options:["Una chiave asimmetrica","Una password condivisa pre-configurata su entrambi i gateway per autenticarsi in IKE","La chiave AES di cifratura","Il certificato digitale"],correct:1,explanation:"PSK: password segreta configurata manualmente su entrambi i peer VPN. Usata in IKE per l'autenticazione reciproca. Più semplice dei certificati ma meno scalabile e meno sicura per grandi deployment."},
  {id:211,type:"mc",topic:"Modalità",text:"Quale modalità IPsec aggiunge un header IP completo al pacchetto?",options:["Trasporto","Tunnel","Entrambe","Nessuna"],correct:1,explanation:"Tunnel mode: aggiunge un nuovo header IP esterno (con IP del gateway). L'intero pacchetto originale (header + payload) viene cifrato come payload del nuovo pacchetto."},
  {id:212,type:"mc",topic:"SA",text:"Dopo quanto tempo scade tipicamente una SA IPsec?",options:["Mai","Secondo un lifetime configurato (es. 1 ora o 1 GB di dati)","Dopo 24 ore sempre","Dopo il logout dell'utente"],correct:1,explanation:"Le SA hanno un lifetime configurabile: in tempo (es. 3600s = 1 ora) o in volume di dati (es. 4GB). Alla scadenza, IKE Fase 2 negozia automaticamente nuove SA senza interrompere la connessione."},
  {id:213,type:"mc",topic:"Protocolli",text:"Cosa è l'Anti-Replay protection in IPsec?",options:["Protezione contro pacchetti duplicati/reinjettati","Cifratura delle repliche","Backup automatico","Un tipo di autenticazione"],correct:0,explanation:"Anti-replay: IPsec assegna un sequence number a ogni pacchetto. Il ricevente mantiene una finestra di sequence number accettati — pacchetti fuori finestra o duplicati vengono scartati, prevenendo replay attack."},
  {id:214,type:"mc",topic:"IKE",text:"Quale porta usa NAT-T (NAT Traversal) per IPsec/ESP?",options:["UDP 500","UDP 4500","TCP 443","UDP 1194"],correct:1,explanation:"NAT-T: incapsula ESP dentro UDP porta 4500 per attraversare dispositivi NAT. IKE usa UDP 500 normalmente, ma quando rileva NAT (via NAT-D payload), IKE e ESP passano a UDP 4500."},
  {id:215,type:"mc",topic:"SA",text:"Il SPD (Security Policy Database) in IPsec definisce:",options:["Le chiavi crittografiche","Le policy: quale traffico proteggere con IPsec e come","I peer VPN disponibili","Il routing del traffico"],correct:1,explanation:"SPD: definisce le policy di sicurezza — per quale traffico applicare IPsec (by-pass, discard, protect). Ad esempio: 'tutto il traffico tra 10.0.0.0/24 e 192.168.0.0/24 deve essere protetto con ESP Tunnel'."},
  {id:216,type:"mc",topic:"IKE",text:"EAP (Extensible Authentication Protocol) in IKEv2 serve per:",options:["Cifrare i dati","Autenticazione avanzata del client (certificati, OTP, RADIUS, LDAP)","Scambio DH","Negoziare le cipher suite"],correct:1,explanation:"EAP in IKEv2: supporta metodi di autenticazione avanzati per il client remoto — EAP-TLS (certificati), EAP-MSCHAPv2 (username/password), EAP-RADIUS (autenticazione RADIUS). Non disponibile in IKEv1."},
  {id:217,type:"mc",topic:"Modalità",text:"In IPsec modalità tunnel tra due gateway, chi esegue la cifratura?",options:["Gli host finali","I gateway VPN (router/firewall con IPsec)","Il server DNS","Il router ISP"],correct:1,explanation:"In tunnel mode site-to-site: sono i gateway VPN (es. i firewall delle due sedi) ad eseguire la cifratura/decifratura. Gli host finali (PC, server) non sono a conoscenza della VPN."},
  {id:218,type:"mc",topic:"Protocolli",text:"Quale header viene autenticato da AH ma NON da ESP?",options:["TCP header","UDP payload","Header IP esterno","Payload cifrato"],correct:2,explanation:"AH autentica l'intero pacchetto incluso l'header IP esterno (tranne i campi mutabili). ESP autentica solo il payload (e l'header ESP) ma NON l'header IP esterno — per questo ESP è compatibile con NAT."},
  {id:219,type:"mc",topic:"IKE",text:"Cosa negozia IKE Fase 1 specificamente?",options:["Le SA per il traffico dati","L'ISAKMP SA (tunnel di gestione) per proteggere la Fase 2","I certificati degli utenti","La tabella di routing"],correct:1,explanation:"IKE Fase 1: negozia i parametri (hash, DH group, cifratura, lifetime), esegue DH, si autentica (PSK/certificati) e stabilisce l'ISAKMP SA — il tunnel sicuro entro cui avverrà la Fase 2."},
  {id:220,type:"mc",topic:"SA",text:"Quale comando Cisco mostra le SA IPsec attive?",options:["show ip route","show crypto isakmp sa","show ip nat translations","show interfaces"],correct:1,explanation:"'show crypto isakmp sa': mostra le SA IKE (Fase 1). 'show crypto ipsec sa': mostra le SA IPsec (Fase 2). 'show crypto map': mostra la configurazione crypto map."},
  {id:221,type:"mc",topic:"IKE",text:"PFS (Perfect Forward Secrecy) esegue un nuovo DH in quale fase?",options:["IKE Fase 1","IKE Fase 2 (Quick Mode)","Durante il trasferimento dati","Al riavvio del router"],correct:1,explanation:"PFS in IKE Fase 2: viene eseguito un nuovo scambio DH per ogni coppia di SA. Le chiavi di sessione sono indipendenti dalla Fase 1 — se la chiave di Fase 1 viene compromessa, non espone le SA di Fase 2."},
  {id:222,type:"mc",topic:"Protocolli",text:"IPsec in quale scenario è preferito rispetto a SSL/TLS VPN?",options:["Accesso da browser","Dispositivi mobili consumer","VPN site-to-site tra router aziendali","App web in cloud"],correct:2,explanation:"IPsec è preferito per VPN site-to-site tra router/firewall aziendali: è trasparente alle applicazioni, ad alte prestazioni, e standard nei dispositivi di rete enterprise (Cisco, Juniper, Palo Alto)."},
  {id:223,type:"mc",topic:"SA",text:"Cosa accade quando la SA IPsec scade?",options:["La VPN si disconnette definitivamente","IKE negozia automaticamente nuove SA senza interruzione","Il gateway si riavvia","Si usa la SA precedente fino al prossimo avvio"],correct:1,explanation:"Prima della scadenza della SA, IKE Fase 2 negozia automaticamente nuove SA (rekeying). Il traffico passa alle nuove SA senza interruzione della VPN."},
  {id:224,type:"mc",topic:"Modalità",text:"Quale scenario usa IPsec trasporto (transport mode)?",options:["VPN tra sedi remote","IPsec tra due server nello stesso datacenter che devono comunicare in modo sicuro","Internet pubblica","Solo con IPv6"],correct:1,explanation:"Trasporto: host-to-host. Es. due server nel datacenter che devono comunicare in modo sicuro (DB server e web server). Gli IP originali sono visibili ma il payload è protetto."},
  {id:225,type:"mc",topic:"IKE",text:"ISAKMP sta per:",options:["Internet Security Association and Key Management Protocol","Internet Standard Algorithm for Key Management","Internal Security Access Key Module Protocol","Integrated Security Algorithm Keying Method Protocol"],correct:0,explanation:"ISAKMP: Internet Security Association and Key Management Protocol. Definisce il framework per stabilire le SA. IKE implementa ISAKMP."},
  {id:226,type:"mc",topic:"Protocolli",text:"Quale protocollo IPsec supporta sia cifratura che integrità in un unico header?",options:["AH","ESP","IKE","ISAKMP"],correct:1,explanation:"ESP (Encapsulating Security Payload): unico header che fornisce sia cifratura del payload (es. AES-256) che autenticazione/integrità (es. HMAC-SHA256). AH fornisce solo integrità/autenticazione."},
  {id:227,type:"mc",topic:"SA",text:"La 'lifetime' delle SA IPsec può essere misurata in:",options:["Solo secondi","Solo bytes","Secondi o kilobytes (volume di dati)","Solo numero di pacchetti"],correct:2,explanation:"Lifetime delle SA: può essere configurata in secondi (es. 3600s = 1h) o in kilobytes (es. 4096000 KB = 4GB). Scade appena uno dei due limiti viene raggiunto. Poi si rinegozia."},
  {id:228,type:"mc",topic:"IKE",text:"Quale attributo negoziato in IKE determina l'algoritmo di cifratura della SA?",options:["Authentication Algorithm","Encryption Algorithm (Transform Set)","DH Group","Lifetime"],correct:1,explanation:"Il Transform Set in IKE definisce: algoritmo di cifratura (AES, 3DES), algoritmo di hash/autenticazione (SHA-256, MD5), modalità (tunnel/trasporto). Si negozia in Fase 1 per ISAKMP SA e in Fase 2 per le SA dati."},
  {id:229,type:"mc",topic:"Protocolli",text:"Quale protocollo IPsec viene usato per tunnel VPN con NAT?",options:["AH","ESP con NAT-T","AH + ESP","Solo IKE"],correct:1,explanation:"ESP con NAT-T: incapsula ESP dentro UDP 4500 per attraversare NAT. AH è incompatibile con NAT. ESP senza NAT-T funziona solo senza NAT."},
],

"firewall":[
  {id:200,type:"mc",topic:"Policy",text:"Il principio del 'least privilege' si applica ai firewall come:",options:["Default-Allow","Default-Deny","Trust-all","Permit-all"],correct:1,explanation:"Least privilege: solo i permessi strettamente necessari. Nel firewall: Default-Deny + apertura esplicita solo di ciò che serve. Riduce la superficie d'attacco."},
  {id:201,type:"mc",topic:"Tipologie",text:"Un NGFW aggiunge rispetto a un firewall SPI tradizionale:",options:["Solo velocità","DPI + IDS/IPS + App-ID + SSL inspection + policy per utente","Solo IPv6","Solo NAT"],correct:1,explanation:"NGFW: oltre a SPI aggiunge Deep Packet Inspection (contenuto), IDS/IPS integrato, identificazione applicazioni (App-ID — anche su porte non standard), SSL inspection (decifra HTTPS), policy basate sull'utente AD."},
  {id:202,type:"mc",topic:"SPI",text:"In quale stato TCP il firewall SPI considera una connessione stabilita?",options:["Solo SYN","SYN → SYN-ACK → ACK completato","Solo dopo il FIN","Dopo il primo pacchetto"],correct:1,explanation:"SPI traccia il three-way handshake: vede SYN (NEW), poi SYN-ACK (ESTABLISHED parziale), poi ACK (ESTABLISHED). Solo connessioni completamente stabilite sono accettate."},
  {id:203,type:"mc",topic:"DMZ",text:"Quale traffico dovrebbe essere permesso dal firewall interno (DMZ → LAN)?",options:["Tutto il traffico dalla DMZ","Nessun traffico","Solo il traffico esplicitamente necessario (es. risposte DB)","Solo HTTP"],correct:2,explanation:"Principio DMZ: il firewall interno permette dalla DMZ SOLO il traffico strettamente necessario verso la LAN (es. le risposte del database server che serve il web in DMZ). Tutto il resto viene bloccato."},
  {id:204,type:"mc",topic:"Tipologie",text:"Quale tipo di firewall è più efficace contro attacchi applicativi (SQLi, XSS)?",options:["Packet Filter","SPI","Application Gateway / WAF","Circuit-Level Gateway"],correct:2,explanation:"Web Application Firewall (WAF) / Application Gateway L7: analizza il contenuto HTTP/HTTPS, rileva pattern di attacchi applicativi (SQL injection, XSS, CSRF). Un packet filter o SPI non vede il contenuto applicativo."},
  {id:205,type:"mc",topic:"Architetture",text:"Un 'dual-homed bastion host' ha:",options:["Una sola interfaccia","Due interfacce di rete (una LAN, una Internet) — tutto il traffico deve passare per lui","Tre interfacce","Solo una loopback"],correct:1,explanation:"Dual-homed bastion host: due NIC — una verso Internet, una verso la LAN interna. Tutto il traffico passa attraverso il bastion host. Svantaggio: single point of failure."},
  {id:206,type:"tf",topic:"Limiti",text:"Un firewall NGFW con SSL inspection può analizzare il traffico HTTPS cifrato.",options:["Vero","Falso"],correct:0,explanation:"VERO. SSL inspection (SSL/TLS interception): il firewall si interpone come proxy, decifrando il traffico HTTPS, analizzandone il contenuto (DPI), e re-cifrando prima di inoltrarlo. Genera un certificato dinamico per ogni sessione."},
  {id:207,type:"mc",topic:"Tipologie",text:"Il Packet Filter è stateless. Cosa significa?",options:["Non filtra pacchetti UDP","Non ricorda le connessioni precedenti — ogni pacchetto valutato indipendentemente","Non supporta IPv6","Non usa regole ACL"],correct:1,explanation:"Stateless (senza stato): ogni pacchetto viene valutato in modo indipendente, senza tener conto della storia della connessione. Non sa se un pacchetto è parte di una connessione legittima o no."},
  {id:208,type:"mc",topic:"SPI",text:"La state table di SPI viene aggiornata ogni volta che:",options:["Si riavvia il firewall","Arriva un nuovo pacchetto che apre/chiude/modifica una connessione","Ogni 30 secondi","Solo all'amministratore"],correct:1,explanation:"La state table viene aggiornata dinamicamente: nuova connessione TCP (SYN) → nuova entry. Connessione chiusa (FIN/RST) o timeout → entry rimossa. Pacchetti in risposta → entry aggiornata."},
  {id:209,type:"mc",topic:"DMZ",text:"Perché i server DNS pubblici vengono messi nella DMZ?",options:["Per velocizzare le risoluzioni","Devono essere accessibili da Internet ma non devono avere accesso alla LAN interna","Per risparmiare IP","Per usare meno CPU"],correct:1,explanation:"Server DNS pubblici: rispondono alle query da Internet (necessario per la risoluzione del dominio aziendale). Se compromessi, non devono poter raggiungere la LAN interna. La DMZ fornisce questo isolamento."},
  {id:210,type:"mc",topic:"Policy",text:"Quale tecnica riduce la superficie d'attacco configurando il firewall?",options:["Default-Allow + logging","Default-Deny + apertura minima necessaria","Blocco solo delle porte sopra 1024","Permit-all con monitoraggio"],correct:1,explanation:"Default-Deny + apertura minima: solo le porte/servizi strettamente necessari sono aperti. Riduce la superficie d'attacco: ogni porta chiusa è un potenziale vettore di attacco eliminato."},
  {id:211,type:"mc",topic:"Tipologie",text:"Quale firewall analizza il traffico HTTP e può bloccare download di malware?",options:["Packet Filter","SPI","DPI (Deep Packet Inspection)","Stateless"],correct:2,explanation:"DPI: analizza il payload dei pacchetti fino al livello applicativo. Può: identificare virus nel traffico HTTP, bloccare file con estensioni pericolose, rilevare tunneling di protocolli nascosti."},
  {id:212,type:"mc",topic:"Architetture",text:"In una rete con DMZ, quale server NON dovrebbe mai essere nella DMZ?",options:["Web server","Mail server","Database server con dati sensibili","DNS server"],correct:2,explanation:"Il database server con dati sensibili appartiene nella LAN interna, non nella DMZ. I server DMZ devono avere accesso minimo alla LAN. Il web server in DMZ accede al DB nella LAN solo tramite porta specifica."},
  {id:213,type:"mc",topic:"SPI",text:"Qual è il vantaggio del SPI rispetto al Packet Filter contro il port scanning?",options:["SPI è più veloce","SPI traccia lo stato — può rilevare scan di porte (es. molte SYN senza ACK)","SPI cifra il traffico","SPI usa meno CPU"],correct:1,explanation:"SPI può rilevare comportamenti anomali: es. molte SYN verso porte diverse senza ACK = port scan. Il firewall può bloccare l'IP sorgente. Un packet filter semplice non ha questa visibilità."},
  {id:214,type:"mc",topic:"Tipologie",text:"Quale livello OSI corrisponde al Circuit-Level Gateway?",options:["L3 Network","L4 Transport","L5 Session","L7 Application"],correct:2,explanation:"Circuit-Level Gateway: livello 5 (Sessione). Monitora l'handshake e lo stato delle sessioni TCP/UDP ma non ispeziona il payload. Nasconde la struttura interna della rete."},
  {id:215,type:"mc",topic:"DMZ",text:"Un web application firewall (WAF) si posiziona tipicamente:",options:["Tra Internet e i DNS server","Davanti ai web server per filtrare il traffico HTTP/HTTPS applicativo","Tra la LAN e Internet","Dentro i server web"],correct:1,explanation:"WAF: posizionato davanti ai web server (in DMZ o in cloud). Analizza il traffico HTTP/HTTPS applicativo, blocca attacchi SQL injection, XSS, CSRF, path traversal, ecc."},
  {id:216,type:"mc",topic:"Policy",text:"Cosa è il 'security policy' di un firewall?",options:["La password dell'amministratore","L'insieme di regole che definiscono quale traffico è permesso o bloccato","Il software del firewall","Il tipo di hardware"],correct:1,explanation:"Security policy: l'insieme delle regole ACL che il firewall applica al traffico. Definisce: cosa è permesso (permit), cosa è bloccato (deny), in quale direzione, da/verso quali host/reti/porte."},
  {id:217,type:"mc",topic:"Architetture",text:"Quale architettura firewall ha un singolo punto di failure?",options:["Screened Subnet con 2 firewall","Dual-Homed Bastion Host (tutto passa da un singolo host)","Packet Filter + SPI in serie","NGFW cluster"],correct:1,explanation:"Dual-Homed Bastion Host: tutto il traffico deve passare attraverso un singolo host. Se cade, la rete è isolata. Il Screened Subnet con 2 firewall è più resiliente (se cade il FW esterno, il FW interno protegge ancora la LAN)."},
  {id:218,type:"mc",topic:"Tipologie",text:"Quale è il principale svantaggio di un Proxy/Application Gateway?",options:["Non supporta NAT","Richiede un proxy separato per ogni protocollo e introduce latenza","Non usa regole","Non supporta IPv6"],correct:1,explanation:"Application Gateway: richie un proxy per ogni protocollo supportato (HTTP proxy, FTP proxy, SMTP proxy, ecc.) e introduce latenza aggiuntiva (due connessioni invece di una). Più sicuro ma più lento e complesso."},
  {id:219,type:"mc",topic:"DMZ",text:"Il server SMTP (mail server) in DMZ può ricevere email da Internet su porta:",options:["80","443","25","110"],correct:2,explanation:"SMTP usa la porta TCP 25 per la ricezione di email da altri server (server-to-server). Il firewall esterno permette TCP 25 verso il mail server in DMZ. La porta 25 verso la LAN interna deve essere bloccata."},
  {id:220,type:"mc",topic:"Policy",text:"Il logging nei firewall serve principalmente per:",options:["Rallentare il traffico","Audit di sicurezza, forensics e rilevamento anomalie","Aumentare la sicurezza crittografica","Solo per statistiche"],correct:1,explanation:"Il logging è fondamentale per: audit di sicurezza (chi ha acceduto a cosa), forensics (investigare incidenti), rilevamento anomalie (pattern sospetti nei log), compliance (GDPR, PCI-DSS richiedono log)."},
  {id:221,type:"mc",topic:"Tipologie",text:"App-ID in un NGFW identifica l'applicazione basandosi su:",options:["Solo la porta destinazione","Firma del comportamento/payload dell'applicazione, indipendentemente dalla porta","Solo il protocollo IP","Il nome DNS"],correct:1,explanation:"App-ID: analizza il comportamento del traffico e il payload per identificare l'applicazione. Es. può rilevare Facebook anche se usa porta 443, o Skype anche se usa porte non standard."},
  {id:222,type:"mc",topic:"SPI",text:"Un firewall SPI può bloccare una sessione TCP a metà se:",options:["Il TTL scade","Il firewall viene riavviato","Rileva sequence number anomali o flag TCP inaspettati","La banda è satura"],correct:2,explanation:"SPI verifica sequence number TCP e flag: un pacchetto RST inaspettato (reset injection), sequence number fuori range, o flag anomali → la sessione viene bloccata come potenzialmente malevola."},
  {id:223,type:"mc",topic:"Architetture",text:"Quale è il vantaggio principale della Screened Subnet rispetto al Dual-Homed Bastion?",options:["È più economica","Due livelli di difesa indipendenti: anche se la DMZ è compromessa, il FW interno protegge la LAN","È più semplice","Non richiede routing"],correct:1,explanation:"Screened Subnet: Internet → FW esterno → DMZ → FW interno → LAN. Se un server DMZ è compromesso, l'attaccante deve ancora superare il FW interno per raggiungere la LAN. Defense in depth."},
  {id:224,type:"mc",topic:"Limiti",text:"Quale attacco un firewall perimetrale non può prevenire?",options:["Port scanning da Internet","Accesso non autorizzato a porte aperte","Lateral movement di malware già presente nella LAN","DDoS da Internet"],correct:2,explanation:"Lateral movement (movimento laterale): malware già all'interno della LAN si sposta tra host usando porte interne (es. SMB, RDP). Il firewall perimetrale non vede il traffico interno — serve segmentazione con micro-firewall o VLAN."},
  {id:225,type:"mc",topic:"Tipologie",text:"Qual è la differenza tra IDS e firewall?",options:["Non c'è differenza","IDS analizza e segnala le anomalie, firewall permette/blocca il traffico secondo regole","Firewall usa ML, IDS no","IDS cifra il traffico"],correct:1,explanation:"Firewall: controllo accessi — permette o blocca il traffico secondo policy (ACL). IDS: rilevamento — analizza il traffico per identificare comportamenti sospetti e genera alert. NGFW combina entrambi con IPS."},
  {id:226,type:"mc",topic:"DMZ",text:"Cosa è un 'honey pot' e dove si posiziona?",options:["Un firewall speciale","Un sistema-esca che attira gli attaccanti, tipicamente nella DMZ","Un tipo di VPN","Un server DNS"],correct:1,explanation:"Honey pot: sistema intenzionalmente vulnerabile che simula risorse preziose. Attira gli attaccanti, rallentandoli e permettendo di studiarli. Posizionato in DMZ o in una rete separata per non rischiare la LAN."},
  {id:227,type:"mc",topic:"Policy",text:"Il 'fail-open' in un firewall significa:",options:["In caso di guasto, il firewall blocca tutto il traffico","In caso di guasto, il traffico viene lasciato passare","Il firewall si riavvia automaticamente","Il firewall manda un alert"],correct:1,explanation:"Fail-open: in caso di guasto hardware/software del firewall, il traffico passa senza filtro. Preferito in contesti dove la disponibilità è critica. Fail-close (blocca tutto in caso di guasto) è preferito per la sicurezza."},
  {id:228,type:"mc",topic:"Tipologie",text:"SSL inspection (SSL/TLS decryption) introduce quale rischio?",options:["Rallenta solo HTTPS","Il firewall vede il traffico in chiaro → deve essere protetto; per l'utente appare un certificato del FW","Rompe la crittografia definitivamente","Non introduce rischi"],correct:1,explanation:"SSL inspection: il firewall decifra HTTPS, analizza e re-cifra. Rischi: il firewall deve proteggere le chiavi private generate; l'utente vede il certificato del FW invece di quello del sito → possibile impersonazione."},
  {id:229,type:"mc",topic:"Architetture",text:"In quale zona si posiziona un 'reverse proxy'?",options:["LAN interna","DMZ — riceve le richieste da Internet e le inoltra ai server interni","Internet","Backbone router"],correct:1,explanation:"Reverse proxy in DMZ: riceve le richieste HTTP/HTTPS da Internet, le analizza, e le invia al server web nella LAN interna. Nasconde la struttura interna, bilancia il carico, offre cache e SSL termination."},
],

"acl":[
  {id:200,type:"mc",topic:"Funzionamento",text:"Quale è l'ordine di processing di una ACL Cisco quando arriva un pacchetto?",options:["Bottom-up: ultima regola prima","Top-down: prima ACE che corrisponde vince","Ordine casuale","Per priorità numerica"],correct:1,explanation:"Top-down: il router valuta le ACE in ordine dall'alto. Appena trova una corrispondenza (match), applica l'azione (permit/deny) e si ferma. Le ACE successive non vengono valutate."},
  {id:201,type:"mc",topic:"Standard vs Estesa",text:"Quale ACL può bloccare solo il traffico Telnet senza bloccare tutto il traffico da un host?",options:["ACL Standard","ACL Estesa (specifica protocollo TCP porta 23)","Entrambe","Nessuna delle due"],correct:1,explanation:"ACL Estesa: può specificare protocollo (TCP) e porta (23 = Telnet). Es: 'access-list 110 deny tcp any any eq 23'. ACL Standard filtra solo IP sorgente e bloccherebbe tutto il traffico da quell'host."},
  {id:202,type:"mc",topic:"Wildcard",text:"Cosa permette la regola 'permit ip 172.16.0.0 0.0.255.255 any'?",options:["Solo i pacchetti da 172.16.0.0","Tutti i pacchetti da qualsiasi IP nel range 172.16.0.0–172.16.255.255","Solo i pacchetti da 172.16.255.255","Tutti i pacchetti"],correct:1,explanation:"Wildcard 0.0.255.255: i primi 2 ottetti fissi (172.16), gli ultimi 2 liberi. Permette tutto il traffico proveniente dal range 172.16.0.0–172.16.255.255 (/16)."},
  {id:203,type:"mc",topic:"Deny implicito",text:"Qual è la conseguenza di dimenticare 'permit ip any any' alla fine di una ACL?",options:["La ACL è più sicura","Tutto il traffico non esplicitamente permesso viene bloccato (deny implicito)","La ACL non funziona","Solo il broadcast viene bloccato"],correct:1,explanation:"Deny implicito: se non c'è 'permit ip any any' finale, tutto il traffico che non corrisponde alle ACE esplicite viene scartato silenziosamente. Può bloccare traffico legittimo inaspettato."},
  {id:204,type:"mc",topic:"Sintassi",text:"La sintassi corretta per bloccare ping (ICMP) da 10.0.0.0/8 è:",options:["access-list 110 deny udp 10.0.0.0 0.255.255.255 any","access-list 110 deny icmp 10.0.0.0 0.255.255.255 any","access-list 10 deny 10.0.0.0","access-list 110 block icmp 10.0.0.0"],correct:1,explanation:"ACL Estesa per ICMP: 'access-list 110 deny icmp [sorgente] [wildcard] [destinazione]'. Il protocollo è 'icmp' (non TCP o UDP)."},
  {id:205,type:"mc",topic:"Posizionamento",text:"Se applichi una ACL Standard vicino alla sorgente per bloccare 192.168.1.0/24 verso 10.0.0.5, cosa succede?",options:["Blocca solo il traffico verso 10.0.0.5","Blocca tutto il traffico da 192.168.1.0/24 verso qualsiasi destinazione","Non ha effetto","Blocca solo HTTP"],correct:1,explanation:"Questo è il problema del posizionamento errato: ACL Standard vicino alla sorgente filtra l'IP sorgente senza distinguere la destinazione. Blocca tutto il traffico da 192.168.1.0/24, anche verso altri host leciti."},
  {id:206,type:"mc",topic:"Sintassi",text:"Quale keyword Cisco equivale a 'IP 0.0.0.0 wildcard 255.255.255.255'?",options:["host","none","any","all"],correct:2,explanation:"'any' = 0.0.0.0 255.255.255.255 (tutti i bit ignorati = corrisponde a qualsiasi indirizzo IP). Usato come 'permit ip any any' per permettere tutto il traffico non bloccato da regole precedenti."},
  {id:207,type:"mc",topic:"Verifica",text:"Come si resettano i contatori 'match' di una ACL Cisco?",options:["Cancellando e ricreando la ACL","clear ip access-list counters [nome/numero]","reload","no ip access-list"],correct:1,explanation:"'clear ip access-list counters [ACL]' resetta i contatori di match per quella ACL senza cancellarla. Utile per testare se le regole vengono colpite dopo una modifica."},
  {id:208,type:"mc",topic:"Standard vs Estesa",text:"Quale numero di ACL si usa per una ACL Extended Named?",options:["1-99","100-199","Un nome stringa","Nessun numero"],correct:2,explanation:"ACL Named usano un nome stringa invece di un numero: 'ip access-list extended BLOCCA_TELNET'. Sia le ACL Standard che Estese possono essere nominative. Vantaggio: nomi descrittivi e possibilità di modificare singole ACE."},
  {id:209,type:"mc",topic:"Posizionamento",text:"Una ACL Estesa che blocca SMTP (porta 25) in uscita va posizionata:",options:["Vicino alla destinazione, inbound","Vicino alla sorgente, inbound","Vicino alla sorgente, outbound","Non importa la posizione"],correct:1,explanation:"ACL Estesa vicino alla sorgente, inbound: blocca il traffico SMTP alla sorgente appena entra nell'interfaccia del router, prima che venga instradato. Il traffico non consuma risorse di routing."},
  {id:210,type:"mc",topic:"Sintassi",text:"Il comando per verificare le ACL con contatori match è:",options:["show access-list","show ip access-lists","show acl","debug ip access-list"],correct:1,explanation:"'show ip access-lists' (o 'show access-lists'): mostra tutte le ACL configurate con i contatori di match per ogni ACE. Permette di verificare quali regole vengono colpite dal traffico reale."},
  {id:211,type:"mc",topic:"Funzionamento",text:"Quante ACL si possono applicare per direzione per interfaccia?",options:["Illimitate","2 (una inbound, una outbound)","1 per direzione (max 2 totali)","Solo 1 in totale"],correct:2,explanation:"Cisco IOS: una sola ACL per direzione per interfaccia. Es: fa0/0 può avere una ACL 'in' e una 'out', ma non due ACL 'in'. Se si tenta di applicarne una seconda nella stessa direzione, sovrascrive la precedente."},
  {id:212,type:"mc",topic:"Wildcard",text:"Wildcard 0.0.0.3 corrisponde a quale CIDR?",options:["/28","/30","/29","/27"],correct:1,explanation:"Wildcard 0.0.0.3: 2 bit liberi nell'ultimo ottetto (00000011 = 3). Subnet mask = 255.255.255.252 = /30. Range di 4 indirizzi (2 host + rete + broadcast)."},
  {id:213,type:"mc",topic:"Sintassi",text:"Quale comando applica la ACL 'MIAACL' inbound sull'interfaccia?",options:["ip access-list MIAACL in","ip access-group MIAACL in","access-group MIAACL inbound","ip filter MIAACL in"],correct:1,explanation:"'ip access-group [nome/numero] [in|out]' applicato sotto un'interfaccia. Il comando 'access-group' senza 'ip' non esiste nelle ACL IP."},
  {id:214,type:"mc",topic:"Standard vs Estesa",text:"Perché le ACL Standard non distinguono per destinazione?",options:["Limitazione di Cisco","Per design: filtrano solo l'IP sorgente, semplificando la configurazione","Per sicurezza","Per compatibilità con IPv6"],correct:1,explanation:"ACL Standard (numeri 1-99): progettate per filtrare solo l'IP sorgente. Semplici e veloci da processare. Per filtrare per destinazione/porta serve ACL Estesa (100-199)."},
  {id:215,type:"mc",topic:"Funzionamento",text:"Il 'deny implicito' alla fine di ogni ACL Cisco è:",options:["Opzionale","Sempre presente anche se non scritto","Solo nelle ACL Estese","Configurabile on/off"],correct:1,explanation:"Il deny implicito è SEMPRE presente alla fine di ogni ACL Cisco, anche se non appare nel 'show running-config'. Tutto il traffico non esplicitamente permesso viene scartato silenziosamente."},
  {id:216,type:"mc",topic:"Posizionamento",text:"Una ACL che blocca traffico SSH (porta 22) verso il router stesso va applicata:",options:["Su un'interfaccia di uscita","Su tutte le interfacce in ingresso","Solo sulla loopback","Non serve — SSH si blocca diversamente"],correct:1,explanation:"Per bloccare accesso SSH al router: ACL applicata 'in' su tutte le interfacce esposte. In alternativa, usare 'access-class' sulle linee VTY: 'access-class ACL_SSH in' per filtrare l'accesso SSH/Telnet alle linee virtuali."},
  {id:217,type:"mc",topic:"Verifica",text:"'debug ip packet [ACL]' in Cisco IOS serve a:",options:["Mostrare la configurazione ACL","Mostrare in real-time i pacchetti che corrispondono alla ACL","Cancellare i contatori","Testare la ACL offline"],correct:1,explanation:"'debug ip packet [ACL]': mostra in tempo reale i pacchetti che corrispondono alla ACL specificata. Utile per il troubleshooting ma genera molto output — usare con filtro ACL e disabilitare subito dopo."},
  {id:218,type:"mc",topic:"Sintassi",text:"La sintassi Cisco per bloccare tutto il traffico da 192.168.5.100 è:",options:["access-list 10 deny ip host 192.168.5.100","access-list 10 deny host 192.168.5.100","access-list 10 deny 192.168.5.100 0.0.0.0","Sia B che C"],correct:3,explanation:"Entrambe le sintassi sono equivalenti: 'deny host 192.168.5.100' e 'deny 192.168.5.100 0.0.0.0' indicano lo stesso IP specifico. 'host' è la keyword abbreviata per wildcard 0.0.0.0."},
  {id:219,type:"mc",topic:"Wildcard",text:"Quale wildcard seleziona solo gli IP pari nell'ultimo ottetto (es. x.x.x.0, x.x.x.2, ...)?",options:["0.0.0.255","0.0.0.254","0.0.0.1","0.0.0.128"],correct:2,explanation:"Wildcard 0.0.0.1: il bit meno significativo dell'ultimo ottetto è libero. Seleziona tutti gli IP dove i 7 bit più significativi corrispondono al valore di riferimento, ma l'ultimo bit è libero → IP pari e dispari con lo stesso prefisso 7-bit."},
  {id:220,type:"mc",topic:"Standard vs Estesa",text:"Una ACL nominativa Extended si crea con quale comando?",options:["access-list extended NOME","ip access-list extended NOME","create access-list NOME extended","ip acl extended NOME"],correct:1,explanation:"'ip access-list extended NOME' in Global Configuration Mode crea una ACL estesa nominativa. Poi si aggiungono le ACE: 'permit tcp ...', 'deny udp ...', ecc."},
  {id:221,type:"mc",topic:"Funzionamento",text:"Se due ACL hanno la stessa ACE ma in ordine diverso, il comportamento è:",options:["Identico — l'ordine non conta","Diverso — l'ordine determina quale regola viene applicata prima","Identico solo per le ACL Standard","Il router sceglie la più specifica"],correct:1,explanation:"L'ordine delle ACE è CRITICO in una ACL. Se 'permit ip any any' è la prima regola, tutto il traffico è permesso e le regole successive non vengono mai valutate. Regole specifiche devono precedere quelle generali."},
  {id:222,type:"mc",topic:"Sintassi",text:"Per bloccare HTTP in uscita verso 8.8.8.8, l'ACL Estesa corretta è:",options:["access-list 110 deny tcp any host 8.8.8.8 eq 80","access-list 10 deny any 8.8.8.8","access-list 110 deny http any 8.8.8.8","access-list 110 deny udp any host 8.8.8.8 eq 80"],correct:0,explanation:"'access-list 110 deny tcp any host 8.8.8.8 eq 80': protocollo TCP, sorgente any, destinazione esatta 8.8.8.8 (keyword 'host'), porta 80 (HTTP)."},
  {id:223,type:"mc",topic:"Verifica",text:"Quale output di 'show ip access-lists' indica che una regola non viene mai applicata?",options:["Contatore di match = 0","Contatore di match > 0","La regola non appare","Il router dà errore"],correct:0,explanation:"Match counter = 0: quella ACE non ha mai corrisposto a nessun pacchetto. Può indicare: la regola è troppo specifica, il traffico non arriva da quella direzione, o la regola è irraggiungibile (una regola precedente cattura tutto)."},
  {id:224,type:"mc",topic:"Posizionamento",text:"Un'ACL 'outbound' su fa0/0 viene processata:",options:["Prima del lookup della routing table","Dopo il lookup della routing table, prima dell'invio","Contemporaneamente al routing","Non viene mai processata"],correct:1,explanation:"Outbound: il pacchetto viene prima instradato (lookup della routing table), poi filtrato dall'ACL prima di uscire dall'interfaccia. Se bloccato, le risorse di routing sono state sprecate. Inbound è più efficiente."},
  {id:225,type:"mc",topic:"Funzionamento",text:"Le ACL Cisco filtrano il traffico che TRANSITA attraverso il router, ma anche:",options:["Solo il traffico in transito","Il traffico generato dal router stesso (non filtrato da ACL sulle interfacce)","Il traffico BGP","Solo il traffico multicast"],correct:1,explanation:"Le ACL sulle interfacce filtrano il traffico che transita (forwarded). Il traffico generato dal router stesso (OSPF Hello, SNMP, SSH di gestione) non viene filtrato dalle ACL di interfaccia — si usa 'access-class' per le VTY line."},
  {id:226,type:"mc",topic:"Wildcard",text:"Quanto vale la wildcard per la maschera 255.255.128.0?",options:["0.0.127.255","0.0.128.0","0.0.255.255","0.255.0.0"],correct:0,explanation:"Wildcard = 255.255.255.255 - 255.255.128.0 = 0.0.127.255. Il terzo ottetto: 255-128=127. Il quarto: 255-0=255."},
  {id:227,type:"mc",topic:"Sintassi",text:"Quale ACE permette solo le risposte TCP (ACK) e non le nuove connessioni (SYN)?",options:["permit tcp any any","permit tcp any any established","deny tcp any any syn","permit tcp established any any"],correct:1,explanation:"'permit tcp any any established': keyword 'established' corrisponde ai pacchetti TCP con flag ACK o RST impostato — ovvero risposte a connessioni già stabilite. Blocca i nuovi SYN."},
  {id:228,type:"mc",topic:"Funzionamento",text:"Quale evento aggiorna i contatori di match di una ACL?",options:["Solo il riavvio del router","Ogni pacchetto che corrisponde all'ACE (match)","Ogni 30 secondi","Solo quando il counter supera 100"],correct:1,explanation:"I contatori si aggiornano in tempo reale: ogni pacchetto che corrisponde a una ACE incrementa il contatore di quella ACE. Utile per monitorare il traffico e verificare il funzionamento della ACL."},
  {id:229,type:"mc",topic:"Sintassi",text:"Per un'ACL Named Extended, come si aggiunge una nuova ACE?",options:["Riscrivendo tutta la ACL","Entrando nella ACL con 'ip access-list extended NOME' e aggiungendo la riga","Con 'append access-list'","Non si possono aggiungere ACE dopo la creazione"],correct:1,explanation:"ACL Named: 'ip access-list extended NOME' apre l'editor della ACL. Si può aggiungere, modificare (con numeri di sequenza) o rimuovere singole ACE con 'no [numero_sequenza]'. Impossibile con le ACL numeriche."},
],

"ids-ips":[
  {id:200,type:"mc",topic:"IDS",text:"Quale tecnica di posizionamento usa un NIDS?",options:["Inline nel percorso del traffico","Port mirroring (SPAN) o TAP fuori dal percorso","Installato su ogni host","Come processo nel kernel del router"],correct:1,explanation:"NIDS passivo: riceve una COPIA del traffico tramite porta SPAN dello switch o TAP hardware. Non è nel percorso del traffico — non può bloccare, solo rilevare."},
  {id:201,type:"mc",topic:"AAA",text:"Quale è il flusso RADIUS per l'autenticazione Wi-Fi 802.1X?",options:["Client→AP→RADIUS→AD→RADIUS→AP→Client","Client→Router→Internet","Client→RADIUS diretto","AP→Client→RADIUS"],correct:0,explanation:"802.1X WPA2-Enterprise: Client (supplicant) → AP (NAS) → RADIUS server → AD/LDAP → RADIUS → AP → Client. L'AP è il NAS che fa da intermediario."},
  {id:202,type:"mc",topic:"IPS",text:"Quale azione dell'IPS causa il maggior impatto sulle prestazioni?",options:["Logging","Drop dei pacchetti","SSL inspection + DPI","Alert email"],correct:2,explanation:"SSL inspection + DPI: il processo di decifrare ogni connessione TLS, analizzare il payload e re-cifrare richiede significativa CPU. Su reti ad alto throughput può diventare un bottleneck."},
  {id:203,type:"mc",topic:"RADIUS",text:"Quale porta usa RADIUS per l'accounting?",options:["1812","1813","49","1645"],correct:1,explanation:"RADIUS: porta 1812 (autenticazione) e 1813 (accounting). Le porte legacy sono 1645 e 1646. TACACS+ usa TCP 49."},
  {id:204,type:"mc",topic:"IDS",text:"Qual è il falso positivo in un IDS?",options:["Attacco reale non rilevato","Traffico legittimo classificato erroneamente come attacco","Attacco rilevato correttamente","Alert non inviato"],correct:1,explanation:"Falso positivo: traffico legittimo che l'IDS classifica come attacco. Causa alert inutili che aumentano il carico sugli analisti. Opposto: falso negativo = attacco reale non rilevato."},
  {id:205,type:"mc",topic:"AAA",text:"L'Authorization in AAA risponde alla domanda:",options:["Chi sei?","Cosa puoi fare?","Cosa hai fatto?","Dove sei?"],correct:1,explanation:"Authorization: 'Cosa puoi fare?' — definisce i permessi dell'utente autenticato: VLAN assegnata, ACL da applicare, comandi permessi (in TACACS+), risorse accessibili."},
  {id:206,type:"mc",topic:"TACACS+",text:"Perché TACACS+ è preferito a RADIUS per l'accesso amministrativo ai dispositivi Cisco?",options:["TACACS+ è più veloce","TACACS+ cifra l'intero payload e separa completamente le 3 funzioni AAA","TACACS+ usa UDP","RADIUS non supporta autenticazione"],correct:1,explanation:"TACACS+ per device management: cifra tutto (più sicuro), separa completamente Auth/Authz/Accounting (flessibilità granulare), supporta autorizzazione per singolo comando IOS — funzione fondamentale per l'accesso amministrativo ai dispositivi."},
  {id:207,type:"mc",topic:"IDS",text:"Un HIDS analizza quali sorgenti di dati?",options:["Solo il traffico di rete","Log di sistema, integrità dei file, processi attivi, chiamate di sistema","Solo log dei firewall","Solo il traffico HTTPS"],correct:1,explanation:"HIDS: log di sistema (syslog, Windows Event Log), integrità dei file critici (es. /etc/passwd, DLL di sistema), processi in esecuzione, chiamate di sistema (syscall), traffico di rete locale."},
  {id:208,type:"mc",topic:"MFA",text:"Quale fattore MFA è vulnerabile al SIM swapping?",options:["TOTP via app","OTP via SMS","U2F hardware","Password"],correct:1,explanation:"SIM swapping: l'attaccante convince l'operatore di trasferire il numero di telefono su una SIM diversa, intercettando gli SMS OTP. TOTP e U2F non dipendono dalla rete mobile."},
  {id:209,type:"mc",topic:"IPS",text:"Quale è il vantaggio di usare sia un IDS che un IPS nella stessa rete?",options:["Nessun vantaggio — uno dei due è sufficiente","IDS per visibilità completa senza latenza, IPS inline per blocco immediato degli attacchi critici","IDS per IPv4, IPS per IPv6","IDS è più economico di IPS"],correct:1,explanation:"IDS (passivo): visibilità completa su tutto il traffico senza latenza. IPS (inline): blocco immediato degli attacchi ad alto rischio. Usarli insieme: IPS su segmenti critici, IDS per visibilità globale."},
  {id:210,type:"mc",topic:"RADIUS",text:"Cosa contiene un messaggio 'Access-Accept' RADIUS?",options:["Solo 'OK'","Conferma di autenticità + attributi (VLAN assegnata, IP pool, policy da applicare)","La password dell'utente","Il MAC address del client"],correct:1,explanation:"Access-Accept: conferma che l'autenticazione è riuscita. Include attributi RADIUS: VLAN da assegnare (Tunnel-Private-Group-ID), indirizzo IP da assegnare, ACL da applicare, timeout di sessione, ecc."},
  {id:211,type:"mc",topic:"IDS",text:"Cosa è il 'baseline' nell'anomaly detection?",options:["Un tipo di firma di attacco","La descrizione del comportamento normale della rete su un periodo di tempo","Il massimo traffico tollerato","Il minimo traffico necessario"],correct:1,explanation:"Baseline: profilo statistico del comportamento normale della rete (volume di traffico, protocolli usati, orari di picco, host più comunicanti). Deviazioni significative dalla baseline vengono segnalate come anomalie."},
  {id:212,type:"mc",topic:"AAA",text:"Quale protocollo AAA è uno standard aperto (non proprietario)?",options:["TACACS+","DIAMETER","RADIUS","Entrambi B e C"],correct:2,explanation:"RADIUS è uno standard aperto (RFC 2865, 2866). TACACS+ è proprietario Cisco. DIAMETER è anche uno standard aperto (RFC 6733) — successore di RADIUS usato nelle reti mobili (4G/5G)."},
  {id:213,type:"mc",topic:"IPS",text:"Cosa è il 'false negative' in un IPS?",options:["Traffico legittimo bloccato","Attacco reale non rilevato né bloccato","Azione eseguita correttamente","Alert inviato inutilmente"],correct:1,explanation:"Falso negativo: l'IPS non rileva un attacco reale. È il peggior scenario — l'attacco passa senza che nessuno se ne accorga. Gli attaccanti usano tecniche di evasion per causare falsi negativi."},
  {id:214,type:"mc",topic:"TACACS+",text:"TACACS+ usa quale protocollo di trasporto?",options:["UDP","TCP porta 49","ICMP","GRE"],correct:1,explanation:"TACACS+ usa TCP porta 49. La scelta di TCP (affidabile, connessione) garantisce la consegna sicura dei messaggi AAA. RADIUS usa UDP."},
  {id:215,type:"mc",topic:"IDS",text:"Quale strumento IDS open source è popolare per HIDS (integrità file)?",options:["Snort","Suricata","OSSEC/Wazuh","Zeek"],correct:2,explanation:"OSSEC (ora Wazuh): HIDS open source che monitora log di sistema, integrità dei file, rootkit, policy compliance. Snort e Suricata sono NIDS. Zeek (ex Bro) è un network analysis framework."},
  {id:216,type:"mc",topic:"MFA",text:"TOTP è definito in quale RFC?",options:["RFC 1918","RFC 6238","RFC 2865","RFC 4301"],correct:1,explanation:"TOTP: RFC 6238 (Time-Based One-Time Password Algorithm). Si basa su HOTP (RFC 4226) aggiungendo il timestamp al posto del counter."},
  {id:217,type:"mc",topic:"IPS",text:"Quale tipo di IPS è posizionato inline all'interno della rete Wi-Fi?",options:["HIPS","NIPS","WIPS","Proxy IPS"],correct:2,explanation:"WIPS (Wireless IPS): monitorizza il traffico Wi-Fi e rileva/blocca rogue AP (access point non autorizzati), attacchi deauthentication, client non autorizzati, ecc."},
  {id:218,type:"mc",topic:"AAA",text:"Quale servizio usa RADIUS per autenticare i dipendenti al Wi-Fi aziendale?",options:["WPA2-Personal (PSK)","WPA2-Enterprise (802.1X con RADIUS)","WEP","WPA3-Personal"],correct:1,explanation:"WPA2-Enterprise (802.1X): ogni dipendente si autentica con le proprie credenziali (username/password o certificato). L'AP verifica le credenziali tramite RADIUS → AD. Più sicuro di WPA2-Personal (PSK condiviso)."},
  {id:219,type:"mc",topic:"IDS",text:"Snort è un esempio di quale tipo di IDS?",options:["HIDS signature-based","NIDS signature-based","Anomaly detection","IPS hardware"],correct:1,explanation:"Snort: NIDS open source signature-based. Analizza il traffico di rete in tempo reale confrontandolo con un database di regole (firme). Può operare come IDS (solo alert) o IPS (inline, blocca il traffico)."},
  {id:220,type:"mc",topic:"MFA",text:"Quale fattore MFA è 'something you are'?",options:["OTP SMS","Password","Chiave hardware","Impronta digitale"],correct:3,explanation:"'Something you are' (Inherence): biometria — impronta digitale, riconoscimento facciale, iride, geometria della mano, voce. È il fattore più difficile da rubare (ma non impossibile con deepfake, ecc.)."},
  {id:221,type:"mc",topic:"RADIUS",text:"Un NAS nel contesto RADIUS è:",options:["Un server di storage","Un Network Access Server (intermediario tra client e RADIUS)","Un tipo di firewall","Un server DNS"],correct:1,explanation:"NAS (Network Access Server): il dispositivo che fa da proxy tra il client che vuole accedere e il server RADIUS. Es: AP Wi-Fi, switch 802.1X, VPN concentrator, NAS telefonico (dial-up)."},
  {id:222,type:"mc",topic:"IDS",text:"Quale è il vantaggio principale dell'anomaly detection rispetto alla signature-based?",options:["Meno falsi positivi","Può rilevare attacchi zero-day (mai visti prima)","Più veloce","Non richiede aggiornamenti"],correct:1,explanation:"Anomaly detection: rileva comportamenti anomali rispetto alla baseline — anche attacchi zero-day non ancora nel database delle firme. Svantaggio: più falsi positivi (comportamenti legittimi inusuali vengono segnalati)."},
  {id:223,type:"mc",topic:"IPS",text:"Quale azione dell'IPS interrompe una connessione TCP malevola?",options:["Drop silenzioso","TCP Reset (invia RST ad entrambi i lati)","Redirect","Blocco DNS"],correct:1,explanation:"TCP Reset: l'IPS invia un pacchetto TCP RST a entrambi i lati della connessione, costringendo entrambi a chiuderla. Più rapido del semplice drop perché le applicazioni vengono notificate immediatamente."},
  {id:224,type:"mc",topic:"AAA",text:"Cosa è il 'Accounting' in AAA?",options:["La fatturazione del provider","La registrazione delle attività dell'utente autenticato (cosa ha fatto, quando, per quanto)","La configurazione dei permessi","L'autenticazione tramite token"],correct:1,explanation:"Accounting: registra tutte le attività post-autenticazione. Es: login 9:15, logout 17:30, trasferimento 2.3 GB, 45 comandi eseguiti (TACACS+). Fondamentale per compliance (GDPR, PCI-DSS) e forensics."},
  {id:225,type:"mc",topic:"IDS",text:"Perché un NIDS non può rilevare traffico HTTPS senza SSL inspection?",options:["Per mancanza di CPU","Il traffico HTTPS è cifrato — il NIDS vede solo dati incomprensibili senza decifrare","NIDS non supporta TCP","HTTPS usa porte non standard"],correct:1,explanation:"HTTPS cifrato: il NIDS vede header IP/TCP (IP, porte, dimensioni pacchetti) ma il payload è cifrato. Senza decifrare TLS, non può analizzare il contenuto HTTP per rilevare attacchi applicativi."},
  {id:226,type:"mc",topic:"MFA",text:"HOTP differisce da TOTP perché:",options:["HOTP usa SHA-512","HOTP usa un counter incrementale invece del timestamp","HOTP dura 60 secondi","HOTP non usa HMAC"],correct:1,explanation:"HOTP (RFC 4226): usa un counter incrementale — il codice cambia ogni volta che viene usato (event-based). TOTP (RFC 6238) usa il timestamp (time-based, cambia ogni 30s). TOTP è più diffuso perché non richiede sincronizzazione del counter."},
  {id:227,type:"mc",topic:"IPS",text:"Dove posizionare l'IPS per massima protezione dei server?",options:["Solo a Internet","Tra il firewall perimetrale e i server (inline)","Solo nella LAN utenti","Come monitor passivo fuori banda"],correct:1,explanation:"IPS inline tra il firewall e i server: dopo che il firewall ha filtrato il traffico secondo le policy, l'IPS analizza in profondità il traffico rimanente per rilevare e bloccare attacchi applicativi."},
  {id:228,type:"mc",topic:"RADIUS",text:"Quale attributo RADIUS assegna una VLAN all'utente autenticato?",options:["User-Name","Framed-IP-Address","Tunnel-Private-Group-ID","Acct-Session-Id"],correct:2,explanation:"Tunnel-Private-Group-ID (attributo 81): specifica la VLAN da assegnare al client. Insieme a Tunnel-Type (13=VLAN) e Tunnel-Medium-Type (6=802), permette all'AP/switch di mettere il client nella VLAN corretta."},
  {id:229,type:"mc",topic:"IDS",text:"Zeek (ex Bro) è principalmente usato come:",options:["Signature-based IPS","Network analysis framework — genera log dettagliati del traffico di rete","HIDS","WAF"],correct:1,explanation:"Zeek: framework di analisi della rete che genera log dettagliati (connessioni, HTTP, DNS, certificati, file trasferiti). Non è un IDS classico ma una piattaforma di analisi usata dai SOC per la visibilità del traffico."},
],

"cloud":[
  {id:200,type:"mc",topic:"Cloud",text:"Il modello 'shared responsibility' nel cloud significa:",options:["Solo il provider è responsabile","Solo il cliente è responsabile","La responsabilità è condivisa: il provider gestisce l'infrastruttura, il cliente gestisce dati e applicazioni","Non c'è responsabilità formale"],correct:2,explanation:"Shared Responsibility Model: il provider gestisce sicurezza dell'infrastruttura (hardware, rete, hypervisor). Il cliente gestisce la sicurezza di: applicazioni, dati, configurazioni, identità, OS (in IaaS)."},
  {id:201,type:"mc",topic:"AD",text:"Kerberos in Active Directory usa quale tipo di autenticazione?",options:["Password in chiaro","Token Ticket (TGT e Service Ticket) — senza trasmettere la password sulla rete","Certificati X.509 direttamente","SAML"],correct:1,explanation:"Kerberos: il client richiede un TGT (Ticket Granting Ticket) al KDC (DC) autenticandosi con un hash della password. Il TGT viene usato per ottenere Service Ticket per ogni servizio senza reinviare la password."},
  {id:202,type:"mc",topic:"Backup",text:"Quale tipo di backup ha il tempo di ripristino più veloce?",options:["Incrementale","Differenziale","Full","Snapshot VM"],correct:3,explanation:"Snapshot VM (es. VMware, Hyper-V): copia istantanea dello stato della VM. Ripristino: secondi/minuti. Backup full tradizionale: minuti/ore. Snapshot non è un backup completo ma un punto di ripristino rapido."},
  {id:203,type:"mc",topic:"Clustering",text:"Il 'heartbeat' nel clustering HA serve a:",options:["Monitorare le prestazioni","Comunicare tra nodi per rilevare se il nodo primario è ancora attivo","Sincronizzare i dati","Bilanciare il carico"],correct:1,explanation:"Heartbeat: messaggi periodici tra i nodi del cluster. Se il nodo standby non riceve heartbeat dal nodo primario per un certo periodo, assume che sia caduto e avvia il failover."},
  {id:204,type:"mc",topic:"Cloud",text:"Quale modello cloud offre applicazioni complete senza nessuna gestione dell'infrastruttura?",options:["IaaS","PaaS","SaaS","CaaS"],correct:2,explanation:"SaaS (Software as a Service): il provider gestisce tutto (infrastruttura, OS, middleware, applicazione). Il cliente usa semplicemente l'applicazione via browser. Es. Gmail, Office 365, Salesforce."},
  {id:205,type:"mc",topic:"AD",text:"Cosa è una OU (Organizational Unit) in Active Directory?",options:["Una unità di misura","Un contenitore logico per organizzare utenti, computer e gruppi del dominio","Un tipo di certificato","Un server di backup"],correct:1,explanation:"OU: oggetto contenitore in AD che organizza gerarchicamente utenti, computer, stampanti, gruppi. Permette di applicare GPO specifiche per reparto/sede senza influenzare gli altri."},
  {id:206,type:"mc",topic:"Backup",text:"Quale regola garantisce la sopravvivenza dei dati a un disastro fisico (incendio del datacenter)?",options:["3 copie su stesso disco","Regola 3-2-1: 1 copia fuori sede","Solo backup su cloud","RAID 6"],correct:1,explanation:"Regola 3-2-1: la copia fuori sede (cloud o datacenter remoto) protegge da disastri fisici che distruggerebbero le copie locali (incendio, alluvione, furto). RAID protegge solo da guasti hardware locale."},
  {id:207,type:"mc",topic:"Clustering",text:"Load balancing in un cluster Active-Active distribuisce il traffico per:",options:["Ridurre i costi","Aumentare throughput e garantire continuità se un nodo cade","Solo ridondanza","Solo sincronizzazione"],correct:1,explanation:"Active-Active load balancing: distribuisce il traffico tra nodi attivi (maggiore throughput), e se un nodo cade, gli altri assorbono il carico (alta disponibilità). Combina prestazioni e resilienza."},
  {id:208,type:"mc",topic:"Cloud",text:"Hybrid Cloud combina:",options:["Solo due cloud pubblici","Infrastruttura on-premise + cloud pubblico/privato","Solo due provider cloud","SaaS + PaaS"],correct:1,explanation:"Hybrid Cloud: combina risorse on-premise con cloud pubblico e/o privato. Permette di tenere dati sensibili on-premise e usare il cloud per carichi variabili o per il disaster recovery."},
  {id:209,type:"mc",topic:"AD",text:"SSO (Single Sign-On) in AD usa quale meccanismo?",options:["Re-inserimento password","Kerberos ticket — un TGT permette di ottenere Service Ticket per tutti i servizi","OAuth solo per cloud","Certificati per ogni accesso"],correct:1,explanation:"SSO AD: dopo il login (ottenimento TGT), il client usa il TGT per ottenere Service Ticket per ogni servizio (file server, Exchange, SharePoint) senza reinserire la password → SSO."},
  {id:210,type:"mc",topic:"Backup",text:"RPO di 0 significa:",options:["Nessun backup necessario","Nessuna perdita di dati tollerata — replica in tempo reale richiesta","Backup ogni 0 secondi","Il sistema non deve mai fermarsi"],correct:1,explanation:"RPO=0: nessun dato perso è accettabile. Richiede replica sincrona in tempo reale (es. database cluster con commit sincrono). Molto costoso. Usato per sistemi finanziari critici."},
  {id:211,type:"mc",topic:"Clustering",text:"Cluster ≠ Backup: un ransomware che cifra i dati...",options:["Viene bloccato dal cluster","Cifra i dati su tutti i nodi simultaneamente perché accedono allo stesso storage","Viene rilevato dal heartbeat","Non può colpire un cluster"],correct:1,explanation:"Il cluster condivide lo stesso storage/filesystem. Un ransomware che accede ai dati condivisi li cifra su tutti i nodi contemporaneamente. Il clustering non protegge dai danni logici ai dati."},
  {id:212,type:"mc",topic:"Cloud",text:"Quale è il vantaggio principale del cloud pay-as-you-go?",options:["Più sicuro di on-premise","Costi proporzionali all'utilizzo reale, scalabilità immediata","Nessuna manutenzione hardware","Maggiore controllo dei dati"],correct:1,explanation:"Pay-as-you-go: si paga solo per le risorse usate. Scalabilità immediata verso l'alto (picchi di traffico) e verso il basso (periodi di bassa attività). Nessun costo fisso per hardware inutilizzato."},
  {id:213,type:"mc",topic:"AD",text:"Quale protocollo usa Azure AD per la federazione con applicazioni cloud?",options:["Kerberos","NTLM","SAML 2.0 e OAuth 2.0","LDAP diretto"],correct:2,explanation:"Azure AD usa SAML 2.0 (per SSO con applicazioni web enterprise), OAuth 2.0 (per autorizzazione API), e OpenID Connect (per autenticazione). Non usa Kerberos/LDAP direttamente per le applicazioni cloud."},
  {id:214,type:"mc",topic:"Clustering",text:"Qual è la differenza tra clustering e replication?",options:["Sono identici","Clustering: più server per alta disponibilità del servizio; Replication: copia dei dati su più siti per DR","Clustering è solo per database","Replication è solo per backup"],correct:1,explanation:"Clustering: più server che offrono lo stesso servizio con failover automatico. Replication: copia asincrona/sincrona dei dati verso un sito remoto. Clustering garantisce availability, replication garantisce DR/RPO."},
  {id:215,type:"mc",topic:"Cloud",text:"Cosa è il 'vendor lock-in' nel cloud?",options:["La sicurezza del vendor","La dipendenza da un singolo provider che rende difficile il cambio","Un tipo di contratto","Un SLA garantito"],correct:1,explanation:"Vendor lock-in: quando si usano servizi/tecnologie proprietarie di un provider, diventa difficile e costoso migrare ad un altro. Soluzione: usare standard aperti, architetture multi-cloud, containerizzazione (Kubernetes)."},
  {id:216,type:"mc",topic:"AD",text:"Cosa è LDAP in Active Directory?",options:["Un tipo di certificato","Protocollo per interrogare e modificare la directory AD (porte 389/636)","Un protocollo di routing","Un tipo di backup"],correct:1,explanation:"LDAP (Lightweight Directory Access Protocol): protocollo standard per interrogare e modificare directory. AD usa LDAP per le query: ricercare utenti, verificare gruppi, recuperare attributi. Porta 389 (LDAP), 636 (LDAPS sicuro)."},
  {id:217,type:"mc",topic:"Backup",text:"Quale backup richiede solo l'ultimo backup differenziale + l'ultimo backup full per il ripristino?",options:["Incrementale","Differenziale","Solo full","Solo snapshot"],correct:1,explanation:"Differenziale: ripristino richiede full + ULTIMO differenziale (che include tutte le modifiche dall'ultimo full). Incrementale richiede full + TUTTI gli incrementali in sequenza → più complesso."},
  {id:218,type:"mc",topic:"Cloud",text:"Quale servizio AWS equivale a IaaS per le macchine virtuali?",options:["AWS Lambda","Amazon EC2","Amazon S3","Amazon RDS"],correct:1,explanation:"Amazon EC2 (Elastic Compute Cloud): macchine virtuali su cloud = IaaS. Lambda = FaaS (serverless). S3 = storage object. RDS = database gestito (PaaS)."},
  {id:219,type:"mc",topic:"AD",text:"Cosa è il 'Domain Controller'?",options:["Il server di posta","Il server che ospita il database AD e gestisce autenticazione/autorizzazione nel dominio","Il router del dominio","Il server web del dominio"],correct:1,explanation:"Domain Controller (DC): server Windows che ospita una copia del database Active Directory e fornisce servizi di autenticazione (Kerberos/NTLM), autorizzazione e replica. Ogni dominio AD deve avere almeno un DC."},
  {id:220,type:"mc",topic:"Clustering",text:"RTO di 2 ore significa:",options:["Il sistema fa backup ogni 2 ore","Il sistema deve essere ripristinato entro 2 ore dal guasto","Si perdono 2 ore di dati","Il sistema è in downtime per 2 ore settimanali"],correct:1,explanation:"RTO (Recovery Time Objective): tempo massimo tollerabile per il ripristino del sistema dopo un guasto. RTO=2h: entro 2 ore dal guasto il sistema deve essere operativo."},
  {id:221,type:"mc",topic:"Cloud",text:"Containerizzazione (Docker/Kubernetes) è considerata PaaS o IaaS?",options:["Solo IaaS","Solo PaaS","Dipende: CaaS (Container as a Service) è tra IaaS e PaaS","SaaS"],correct:2,explanation:"CaaS (Container as a Service): categoria intermedia. L'infrastruttura di container (orchestrazione, networking, storage) è gestita dal provider. Il cliente gestisce i container e le applicazioni."},
  {id:222,type:"mc",topic:"AD",text:"Quale protocollo di autenticazione è considerato legacy in AD ma ancora molto diffuso?",options:["Kerberos","NTLM (NT LAN Manager)","OAuth 2.0","SAML"],correct:1,explanation:"NTLM: protocollo di autenticazione challenge-response Microsoft, predecessore di Kerberos. Ancora usato per: workgroup (senza dominio), autenticazione verso IP diretto (senza nome DNS), sistemi legacy."},
  {id:223,type:"mc",topic:"Clustering",text:"Quale tecnologia permette di migrare una VM tra host fisici senza interruzione del servizio?",options:["RAID","Live Migration (VMware vMotion, Hyper-V Live Migration)","Backup incrementale","Clustering attivo-passivo"],correct:1,explanation:"Live Migration (vMotion in VMware): trasferisce la VM da un host fisico a un altro mentre è in esecuzione, senza interruzione del servizio. Fondamentale per la manutenzione degli host fisici."},
  {id:224,type:"mc",topic:"Cloud",text:"Quale vantaggio ha il cloud per il disaster recovery?",options:["Il cloud non è adatto per il DR","Sito DR in cloud = nessun costo fisso per hardware dedicato che rimane inattivo","Il cloud è meno affidabile dell'on-premise","Non c'è vantaggio"],correct:1,explanation:"DR in cloud: si pagano le risorse cloud solo quando serve (es. dopo un disastro). On-premise DR: si mantiene infrastruttura hardware dedicata sempre accesa ma raramente usata. Il cloud DR riduce i costi fissi."},
  {id:225,type:"mc",topic:"AD",text:"Cosa è un 'Group Policy Object' (GPO)?",options:["Un tipo di certificato di gruppo","Un insieme di impostazioni applicate automaticamente a utenti e computer in un'OU del dominio","Un protocollo di routing per AD","Un tipo di account amministratore"],correct:1,explanation:"GPO: definisce configurazioni di sicurezza, software e ambiente. Es: lunghezza minima password, blocco dello schermo dopo N minuti, blocco porte USB, distribuzione software, configurazione firewall Windows. Applicato automaticamente."},
  {id:226,type:"mc",topic:"Backup",text:"Cosa è il 'backup immutabile'?",options:["Un backup che non può essere modificato o cancellato per un periodo di retention","Un backup cifrato","Un backup su nastro","Un backup manuale"],correct:0,explanation:"Backup immutabile (WORM - Write Once Read Many): una volta scritto, non può essere modificato o cancellato fino alla scadenza del periodo di retention. Protegge contro ransomware che tenta di cancellare anche i backup."},
  {id:227,type:"mc",topic:"Cloud",text:"Quale servizio Microsoft equivale ad Active Directory nel cloud?",options:["Azure DevOps","Azure Active Directory (Azure AD / Entra ID)","Azure SQL","Azure CDN"],correct:1,explanation:"Azure Active Directory (ora Microsoft Entra ID): servizio cloud di identity management. Gestisce autenticazione per applicazioni cloud (Office 365, app SaaS) con OAuth 2.0, SAML, OIDC."},
  {id:228,type:"mc",topic:"Clustering",text:"Un quorum nel clustering serve a:",options:["Bilanciare il carico","Determinare quale nodo ha l'autorità di servire le richieste in caso di split-brain","Sincronizzare i dati","Fare il backup"],correct:1,explanation:"Quorum: meccanismo per prevenire lo split-brain (entrambi i nodi pensano di essere il primario). Il quorum richiede che la maggioranza dei nodi sia d'accordo su chi è il primario, evitando conflitti."},
  {id:229,type:"mc",topic:"Cloud",text:"DevOps nel cloud include tipicamente:",options:["Solo sviluppo","CI/CD pipeline, Infrastructure as Code, containerizzazione, monitoraggio automatizzato","Solo operazioni","Solo sicurezza"],correct:1,explanation:"DevOps cloud: CI/CD (integrazione e deployment continuo), IaC (Terraform, Ansible per gestire infrastruttura come codice), container (Docker/K8s), monitoraggio (Prometheus, Grafana), automazione dei test."},
],

"packet-tracer":[
  {id:200,type:"mc",topic:"Configurazione",text:"Quale comando mostra la configurazione di un'interfaccia specifica?",options:["show interfaces fa0/0","show running-config interface fa0/0","show ip interface brief","show ip route"],correct:0,explanation:"'show interfaces fa0/0' mostra: stato (up/down), IP configurato, velocità, duplex, statistiche pacchetti/errori, MTU. Fondamentale per il troubleshooting dell'interfaccia."},
  {id:201,type:"mc",topic:"IOS",text:"Ctrl+Z in Cisco IOS porta a quale modalità?",options:["User EXEC","Global Config","Privileged EXEC","Interface Config"],correct:2,explanation:"Ctrl+Z (o 'end') porta direttamente al Privileged EXEC (#) da qualsiasi livello di configurazione, saltando tutti i livelli intermedi."},
  {id:202,type:"mc",topic:"Configurazione",text:"Quale comando configura il nome di un router?",options:["set name Router1","hostname Router1","name Router1","router-id Router1"],correct:1,explanation:"'hostname Router1' in Global Configuration Mode imposta il nome del router, visibile nel prompt: 'Router1(config)#'. Utile per identificare il dispositivo nella rete."},
  {id:203,type:"mc",topic:"Comandi",text:"'show version' in Cisco IOS mostra:",options:["La tabella di routing","Versione IOS, uptime, memoria, tipo di hardware","Le interfacce","Le ACL configurate"],correct:1,explanation:"'show version': versione Cisco IOS, uptime del router, memoria RAM/Flash, tipo di hardware (modello), numero seriale, image file caricata."},
  {id:204,type:"mc",topic:"Configurazione",text:"Quale comando salva la configurazione per sopravvivere al riavvio?",options:["save","write memory (wr)","copy running-config startup-config","Entrambi B e C"],correct:3,explanation:"Sia 'write memory' (o 'wr') che 'copy running-config startup-config' salvano la running-config in NVRAM come startup-config. La startup-config viene caricata all'avvio."},
  {id:205,type:"mc",topic:"IOS",text:"Quale comando permette di filtrare l'output di show con una parola chiave?",options:["show ip route grep 'RIP'","show ip route | include R","show ip route filter R","search ip route R"],correct:1,explanation:"'show ip route | include R': il pipe '|' passa l'output a un filtro. 'include': mostra solo le righe che contengono la stringa. 'exclude': esclude le righe. 'section': mostra sezioni complete."},
  {id:206,type:"mc",topic:"Configurazione",text:"Quale è il comando per disabilitare un'interfaccia su Cisco IOS?",options:["disable","shutdown","no ip address","down"],correct:1,explanation:"'shutdown' (sotto il prompt config-if) disabilita l'interfaccia. 'no shutdown' la abilita. Le interfacce dei router sono shutdown per default."},
  {id:207,type:"mc",topic:"Comandi",text:"Quale comando mostra le statistiche delle traduzioni NAT?",options:["show ip nat translations","show ip nat statistics","show nat","debug ip nat"],correct:1,explanation:"'show ip nat statistics': mostra le statistiche NAT — numero di traduzioni attive, hits (traduzioni effettuate), misses (indirizzi non trovati nella tabella), pool utilizzati."},
  {id:208,type:"mc",topic:"IOS",text:"Come si abilita la password per il privileged EXEC?",options:["password cisco","enable password cisco","enable secret cisco (più sicuro)","set password enable cisco"],correct:2,explanation:"'enable secret cisco': hash MD5 della password. Preferita a 'enable password' (in chiaro nel config). 'enable secret' sovrascrive 'enable password' se entrambe configurate."},
  {id:209,type:"mc",topic:"Configurazione",text:"Per visualizzare le adiacenze OSPF, quale comando si usa?",options:["show ip ospf","show ip ospf neighbor","show ip ospf database","show ip protocols"],correct:1,explanation:"'show ip ospf neighbor': mostra i vicini OSPF con stato (FULL = adiacenza completa), Router-ID, IP, interfaccia. Stato FULL = LSDB sincronizzato."},
  {id:210,type:"mc",topic:"Comandi",text:"Quale comando Cisco verifica il funzionamento di RIPv2?",options:["show ip route","show ip rip database","show ip protocols","Tutti e tre sono utili"],correct:3,explanation:"Per verificare RIPv2: 'show ip protocols' (RIP attivo? Reti? Timer?), 'show ip rip database' (rotte RIP con metriche), 'show ip route' (rotte R nella tabella). Usarli insieme per troubleshooting completo."},
  {id:211,type:"mc",topic:"IOS",text:"Come si visualizza la startup-config (salvata in NVRAM)?",options:["show running-config","show startup-config","show nvram","show config saved"],correct:1,explanation:"'show startup-config': mostra la configurazione salvata in NVRAM che verrà caricata al prossimo avvio. 'show running-config' mostra la configurazione attiva in RAM."},
  {id:212,type:"mc",topic:"Configurazione",text:"Quale protocollo permette a Cisco Packet Tracer di simulare il tempo reale?",options:["Non simula il tempo reale","Realtime Mode (opposto a Simulation Mode)","Solo il modo simulazione","ICMP timer"],correct:1,explanation:"Packet Tracer ha due modalità: Realtime (comportamento quasi real-time, come su dispositivi veri) e Simulation (passo per passo, visualizza ogni pacchetto)."},
  {id:213,type:"mc",topic:"Comandi",text:"Come si accede alla CLI di un router in Packet Tracer?",options:["Click destro → Properties","Click sul router → tab CLI","Doppio click → CLI tab","Solo via console fisica"],correct:1,explanation:"In Packet Tracer: click sul dispositivo → tab 'CLI'. Si accede direttamente alla command line interface, come se fosse connesso via console o SSH."},
  {id:214,type:"mc",topic:"IOS",text:"Cosa è una 'loopback interface' in Cisco IOS?",options:["Un'interfaccia fisica di loopback","Un'interfaccia logica sempre up, usata per router-id OSPF e management","Un'interfaccia per il backup","Un'interfaccia di debug"],correct:1,explanation:"Loopback interface: interfaccia logica (non fisica) sempre up. Usata per: router-id OSPF/BGP, management IP stabile (anche se le interfacce fisiche cambiano), testing. 'interface loopback 0 → ip address 1.1.1.1 255.255.255.255'."},
  {id:215,type:"mc",topic:"Configurazione",text:"Quale cavo si usa per collegare due switch in Packet Tracer?",options:["Straight-through","Crossover","Serial DCE","Fiber"],correct:1,explanation:"Switch-Switch (stesso tipo di dispositivo): cavo crossover. Switch-PC o Switch-Router (dispositivi diversi): cavo straight-through. Sui dispositivi moderni con auto-MDIX, il tipo di cavo è irrilevante."},
  {id:216,type:"mc",topic:"Comandi",text:"Come si disabilita un debug in Cisco IOS?",options:["stop debug","no debug all / undebug all","disable debug","clear debug"],correct:1,explanation:"'undebug all' o 'no debug all' disabilita tutti i debug attivi. Importante: lasciare debug attivi su router di produzione causa overhead CPU e può influire sulle prestazioni."},
  {id:217,type:"mc",topic:"IOS",text:"Quale comando configura un'ACL standard nominativa?",options:["ip access-list standard NOME","access-list standard NOME","create access-list standard NOME","ip access-list NOME standard"],correct:0,explanation:"'ip access-list standard NOME' in Global Config crea una ACL standard nominativa. Poi si aggiungono le ACE: 'permit host X.X.X.X', 'deny X.X.X.X Y.Y.Y.Y', ecc."},
  {id:218,type:"mc",topic:"Configurazione",text:"Quale comando verifica le adiacenze RIP in IOS?",options:["show ip ospf neighbor","show ip rip neighbor","show ip protocols","Nessuno — RIP non ha concetto di 'neighbor'"],correct:3,explanation:"RIP non ha il concetto di 'neighbor' come OSPF. RIP invia update in broadcast/multicast a tutti sulla rete. Si verifica il funzionamento con 'show ip rip database' e 'show ip protocols'."},
  {id:219,type:"mc",topic:"Comandi",text:"'ping 192.168.1.1 source loopback 0' esegue un ping usando come:",options:["Destinazione la loopback","Sorgente l'interfaccia loopback 0 del router","Solo l'interfaccia loopback","Nessun effetto"],correct:1,explanation:"'source loopback 0': il ping viene inviato usando come indirizzo IP sorgente l'IP configurato sulla loopback 0. Utile per testare la raggiungibilità da specifiche interfacce."},
  {id:220,type:"mc",topic:"IOS",text:"Quale abbreviazione di comando IOS mostra la tabella di routing?",options:["sh ip ro","show ip route","sh ip r","Tutti e tre"],correct:3,explanation:"Cisco IOS supporta abbreviazioni: 'show ip route', 'sh ip route', 'sh ip ro', 'sh ip r' sono tutte equivalenti. IOS accetta qualsiasi abbreviazione non ambigua."},
  {id:221,type:"mc",topic:"Configurazione",text:"Quale passaggio manca in questa configurazione interfaccia: interface fa0/0, ip address 10.0.0.1 255.0.0.0 ?",options:["clock rate","encapsulation","no shutdown","ip nat"],correct:2,explanation:"'no shutdown' manca. Le interfacce dei router Cisco sono disabilitate (shutdown) per default. Senza 'no shutdown' l'interfaccia rimane down anche se ha IP configurato."},
  {id:222,type:"mc",topic:"Comandi",text:"Quale output di 'show interfaces fa0/0' indica che il cavo non è collegato?",options:["'up, up'","'up, down'","'administratively down, down'","'down, down'"],correct:3,explanation:"'FastEthernet0/0 is down, line protocol is down': il cavo non è collegato o il dispositivo remoto è spento. 'up, down': cavo collegato ma problema al protocollo. 'administratively down': shutdown configurato."},
  {id:223,type:"mc",topic:"IOS",text:"Come si configura RIP per non annunciare una rete specifica (passive interface)?",options:["no network X.X.X.X","passive-interface fa0/0","disable rip fa0/0","no router rip fa0/0"],correct:1,explanation:"'passive-interface fa0/0': RIP non invia update sull'interfaccia specificata ma la rete rimane nella tabella di routing e viene annunciata agli altri router. Usato per le interfacce verso la LAN utenti (inutile mandare update lì)."},
  {id:224,type:"mc",topic:"Configurazione",text:"Quale sequenza di comandi configura correttamente PAT su Cisco?",options:["Solo 'ip nat inside source'","access-list → ip nat pool/overload → ip nat inside/outside sulle interfacce","Solo 'ip nat overload'","ip nat → configure terminal → overload"],correct:1,explanation:"PAT su Cisco: 1) ACL per identificare gli IP interni da tradurre. 2) 'ip nat inside source list ACL interface INT overload'. 3) 'ip nat inside' sull'interfaccia LAN. 4) 'ip nat outside' sull'interfaccia WAN."},
  {id:225,type:"mc",topic:"Comandi",text:"Quale comando IOS mostra la versione del protocollo RIP configurato?",options:["show ip rip","show ip protocols","show ip rip database","show running-config | section rip"],correct:1,explanation:"'show ip protocols': mostra per RIP — versione (1 o 2), reti annunciate, timer, distanza amministrativa. Utile per verificare che RIPv2 sia configurato correttamente."},
  {id:226,type:"mc",topic:"IOS",text:"Cosa fa il comando 'no ip routing' su un router Cisco?",options:["Disabilita solo OSPF","Trasforma il router in un host (non instrada più pacchetti)","Cancella la tabella di routing","Disabilita le interfacce"],correct:1,explanation:"'no ip routing': disabilita il processo di routing IP sul dispositivo. Il dispositivo smette di instradare pacchetti tra reti diverse e si comporta come un host. Utile per testare o configurare un router come switch L3 semplice."},
  {id:227,type:"mc",topic:"Configurazione",text:"Quale comando verifica che il NAT stia funzionando correttamente?",options:["show ip nat translations","ping dal PC interno verso Internet + show ip nat translations","debug ip nat","Tutti e tre in combinazione"],correct:3,explanation:"Per verificare NAT: 1) ping dal PC interno verso un IP esterno. 2) 'show ip nat translations' (verifica che la traduzione sia nella tabella). 3) 'debug ip nat' per dettagli in tempo reale (se necessario)."},
  {id:228,type:"mc",topic:"IOS",text:"Quale comando configura un messaggio di benvenuto (MOTD) sul router?",options:["banner login","banner motd # messaggio #","message of the day","welcome message"],correct:1,explanation:"'banner motd # Messaggio di benvenuto #': configura il banner MOTD (Message of the Day), mostrato a chiunque tenti di connettersi. Il carattere '#' è il delimitatore (può essere qualsiasi carattere non nel messaggio)."},
  {id:229,type:"mc",topic:"Comandi",text:"Quale comando mostra la configurazione crypto (VPN) attiva su Cisco IOS?",options:["show ip route","show crypto map","show crypto isakmp sa","Sia B che C"],correct:3,explanation:"Per VPN IPsec Cisco: 'show crypto map' mostra la configurazione crypto map. 'show crypto isakmp sa' mostra le SA IKE (Fase 1). 'show crypto ipsec sa' mostra le SA IPsec (Fase 2). Tutti e tre per debugging completo."},
]
};
